  2→
  3→/* ══════════════════════════════════════════════════════════════════════════
  4→   LOGIN PAGE — Editorial Writing Platform Aesthetic
  5→   Inspired by: Medium, Substack, and literary publication aesthetics
  6→   ══════════════════════════════════════════════════════════════════════════ */
  7→
  8→.auth-shell {
  9→    display: grid;
 10→    grid-template-columns: 1fr 1fr;
 11→    min-height: 100svh;
 12→    background-color: var(--bg-primary);
 13→    color: var(--text-primary);
 14→    font-family: var(--font-ui);
 15→    overflow-x: hidden;
 16→}
 17→
 18→/* ── Left Panel: Brand Story ── */
 19→.auth-panel {
 20→    position: relative;
 21→    display: flex;
 22→    flex-direction: column;
 23→    justify-content: center;
 24→    padding: 64px 72px;
 25→    background: var(--bg-card);
 26→    border-right: 1px solid var(--border-card);
 27→    overflow: hidden;
 28→}
 29→
 30→/* Decorative ink blot shapes */
 31→.auth-panel::before {
 32→    content: '';
 33→    position: absolute;
 34→    width: 400px;
 35→    height: 400px;
 36→    border-radius: 47% 53% 61% 39% / 45% 51% 49% 55%;
 37→    background: radial-gradient(
 38→        ellipse at 30% 30%,
 39→        rgba(212, 168, 83, 0.08),
 40→        transparent 70%
 41→    );
 42→    top: -120px;
 43→    left: -100px;
 44→    animation: morph 20s ease-in-out infinite;
 45→}
 46→
 47→.auth-panel::after {
 48→    content: '';
 49→    position: absolute;
 50→    width: 300px;
 51→    height: 300px;
 52→    border-radius: 61% 39% 47% 53% / 49% 55% 45% 51%;
 53→    background: radial-gradient(
 54→        ellipse at 70% 60%,
 55→        rgba(212, 168, 83, 0.06),
 56→        transparent 70%
 57→    );
 58→    bottom: -80px;
 59→    right: 20px;
 60→    animation: morph 25s ease-in-out infinite reverse;
 61→}
 62→
 63→@keyframes morph {
 64→    0%, 100% { border-radius: 47% 53% 61% 39% / 45% 51% 49% 55%; }
 65→    25% { border-radius: 55% 45% 50% 50% / 60% 40% 60% 40%; }
 66→    50% { border-radius: 40% 60% 55% 45% / 50% 55% 45% 50%; }
 67→    75% { border-radius: 60% 40% 45% 55% / 45% 60% 40% 55%; }
 68→}
 69→
 70→.brand {
 71→    font-family: "Playfair Display", serif;
 72→    font-size: 1.1rem;
 73→    font-weight: 600;
 74→    letter-spacing: 0.18em;
 75→    text-transform: uppercase;
 76→    color: var(--accent-amber);
 77→    margin-bottom: 48px;
 78→    position: relative;
 79→    z-index: 1;
 80→}
 81→
 82→.brand::after {
 83→    content: '';
 84→    display: block;
 85→    width: 32px;
 86→    height: 2px;
 87→    background: var(--accent-amber);
 88→    margin-top: 16px;
 89→    opacity: 0.5;
 90→}
 91→
 92→.panel-title {
 93→    font-family: var(--font-serif);
 94→    font-size: clamp(2rem, 4vw, 2.8rem);
 95→    font-weight: 500;
 96→    font-style: italic;
 97→    max-width: 420px;
 98→    line-height: 1.25;
 99→    letter-spacing: -0.02em;
100→    margin: 0 0 24px;
101→    position: relative;
102→    z-index: 1;
103→    color: var(--text-heading);
104→}
105→
106→.panel-copy {
107→    font-family: var(--font-serif);
108→    font-size: 1.1rem;
109→    color: var(--text-body);
110→    max-width: 380px;
111→    line-height: 1.75;
112→    margin: 0 0 32px;
113→    position: relative;
114→    z-index: 1;
115→}
116→
117→.panel-details {
118→    display: flex;
119→    align-items: center;
120→    gap: 20px;
121→    font-family: var(--font-ui);
122→    font-size: 0.72rem;
123→    color: var(--text-muted);
124→    letter-spacing: 0.08em;
125→    text-transform: uppercase;
126→    position: relative;
127→    z-index: 1;
128→}
129→
130→.panel-details::before {
131→    content: '';
132→    display: inline-block;
133→    width: 4px;
134→    height: 4px;
135→    background: var(--accent-amber);
136→    border-radius: 50%;
137→    opacity: 0.6;
138→}
139→
140→/* ── Right Panel: Form Area ── */
141→.auth-form-panel {
142→    display: flex;
143→    align-items: center;
144→    justify-content: center;
145→    padding: 48px;
146→    background: var(--bg-primary);
147→}
148→
149→.auth-form-card {
150→    width: 100%;
151→    max-width: 400px;
152→    display: flex;
153→    flex-direction: column;
154→    gap: 28px;
155→    background: var(--bg-card);
156→    border: 1px solid var(--border-card);
157→    border-radius: 12px;
158→    padding: 40px 36px;
159→    box-shadow: var(--shadow-card-sm);
160→    animation: slideUp 0.5s cubic-bezier(0.16, 1, 0.3, 1) both;
161→}
162→
163→@keyframes slideUp {
164→    from {
165→        opacity: 0;
166→        transform: translateY(16px);
167→    }
168→    to {
169→        opacity: 1;
170→        transform: translateY(0);
171→    }
172→}
173→
174→.form-title {
175→    font-family: "Playfair Display", serif;
176→    font-size: 1.5rem;
177→    font-weight: 600;
178→    letter-spacing: -0.02em;
179→    color: var(--text-heading);
180→    margin-bottom: 4px;
