  4→import { useNavigate } from 'react-router-dom';
  5→import './SettingsPage.css';
  6→
  7→const SettingsPage = () => {
  8→    const { session } = useAuth();
  9→    const navigate = useNavigate();
 10→
 11→    // Password state
 12→    const [currentPassword, setCurrentPassword] = useState('');
 13→    const [newPassword, setNewPassword] = useState('');
 14→    const [confirmPassword, setConfirmPassword] = useState('');
 15→    const [showCurrentPass, setShowCurrentPass] = useState(false);
 16→    const [showNewPass, setShowNewPass] = useState(false);
 17→    const [passwordLoading, setPasswordLoading] = useState(false);
 18→    const [passwordError, setPasswordError] = useState('');
 19→    const [passwordSuccess, setPasswordSuccess] = useState('');
 20→
 21→    // Email state
 22→    const [newEmail, setNewEmail] = useState('');
 23→    const [emailLoading, setEmailLoading] = useState(false);
 24→    const [emailError, setEmailError] = useState('');
 25→    const [emailSuccess, setEmailSuccess] = useState('');
 26→
 27→    const handleChangePassword = async (e) => {
 28→        e.preventDefault();
 29→        setPasswordError('');
 30→        setPasswordSuccess('');
 31→
 32→        if (newPassword.length < 6) {
 33→            return setPasswordError('New password must be at least 6 characters.');
 34→        }
 35→        if (newPassword !== confirmPassword) {
 36→            return setPasswordError('Passwords do not match.');
 37→        }
 38→
 39→        setPasswordLoading(true);
 40→        try {
 41→            // Verify current password
 42→            const { error: signInError } = await supabase.auth.signInWithPassword({
 43→                email: session.user.email,
 44→                password: currentPassword,
 45→            });
 46→            if (signInError) {
 47→                setPasswordLoading(false);
 48→                return setPasswordError('Current password is incorrect.');
 49→            }
 50→
 51→            // Update to new password
 52→            const { error: updateError } = await supabase.auth.updateUser({
 53→                password: newPassword,
 54→            });
 55→            if (updateError) {
 56→                setPasswordLoading(false);
 57→                return setPasswordError(updateError.message);
 58→            }
 59→
 60→            setPasswordSuccess('Password updated successfully.');
 61→            setCurrentPassword('');
 62→            setNewPassword('');
 63→            setConfirmPassword('');
 64→        } catch (err) {
 65→            setPasswordError('Something went wrong. Please try again.');
 66→        } finally {
 67→            setPasswordLoading(false);
 68→        }
 69→    };
 70→
 71→    const handleChangeEmail = async (e) => {
 72→        e.preventDefault();
 73→        setEmailError('');
 74→        setEmailSuccess('');
 75→
 76→        if (!newEmail || !newEmail.includes('@')) {
 77→            return setEmailError('Please enter a valid email address.');
 78→        }
 79→        if (newEmail === session.user.email) {
 80→            return setEmailError('This is already your current email.');
 81→        }
 82→
 83→        setEmailLoading(true);
 84→        try {
 85→            const { error } = await supabase.auth.updateUser({
 86→                email: newEmail,
 87→            });
 88→            if (error) {
 89→                setEmailLoading(false);
 90→                return setEmailError(error.message);
 91→            }
 92→
 93→            setEmailSuccess('Confirmation email sent to ' + newEmail + '. Please check your inbox.');
