 88→        }
 89→        if (newEmail === session.user.email) {
 90→            return setEmailError('This is already your current email.');
 91→        }
 92→
 93→        setEmailLoading(true);
 94→        try {
 95→            const { error } = await supabase.auth.updateUser({
 96→                email: newEmail,
 97→            });
 98→            if (error) {
 99→                setEmailLoading(false);
100→                return setEmailError(error.message);
101→            }
102→
103→            setEmailSuccess('Confirmation email sent to ' + newEmail + '. Please check your inbox.');
104→            setNewEmail('');
105→        } catch (err) {
106→            setEmailError('Something went wrong. Please try again.');
107→        } finally {
108→            setEmailLoading(false);
109→        }
110→    };
111→
112→    if (!session) {
113→        return null;
114→    }
115→
116→    const isPasswordDisabled = (!isRecovery && !currentPassword) || !newPassword || !confirmPassword || passwordLoading;
117→    const isEmailDisabled = !newEmail || emailLoading;
118→
119→    return (
